"use client";

/* ════════════════════════════════════════════════════════════════════════
   FinancialSituationChart — Finance Tier-1 signature instrument.

   Question it answers: "Where will my cash be in 90 days, and is the trend
   growing or shrinking?" — a 180-day cash position chart (90d back, 90d
   ahead) with a SOLID historical line and DASHED projection, plus a
   dedicated cash-flow ribbon at the bottom showing why the balance moves
   (green above zero = cash grew, red below = shrank; SOLID for actual,
   HATCHED for projected).

   Per the Chart Standard §2:
     - viewBox === pixel width (useChartSize)
     - typed CashPoint[] + NetFlowPoint[] data; samples exported
     - hero value readable without hover
     - 4 states: ready/loading/empty/error
     - reduced-motion safe
     - one truth: am I trending up or burning down?
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useMemo, useRef, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";

export type ChartState = "ready" | "loading" | "empty" | "error";

export interface CashPoint {
  /** Day offset from today; negative = past, positive = future */
  day: number;
  /** Cash balance at that day */
  value: number;
}

export interface NetFlowPoint {
  /** Day offset from today */
  day: number;
  /** Net cash flow that period ($K-ish, ±50 typical range) */
  net: number;
}

export interface FinancialSituationChartProps {
  hist?: CashPoint[];
  proj?: CashPoint[];
  netflow?: NetFlowPoint[];
  /** Red dashed runway floor reference line. */
  runwayFloor?: number;
  /** Label shown next to the projection-end square, e.g. "5.8 mo left" */
  endLabelTop?: string;
  endLabelBottom?: string;
  state?: ChartState;
  onTodayClick?: () => void;
}

export const sampleHist: CashPoint[] = [
  { day: -90, value: 720_000 },
  { day: -75, value: 690_000 },
  { day: -60, value: 755_000 },
  { day: -45, value: 810_000 },
  { day: -30, value: 788_000 },
  { day: -15, value: 845_000 },
  { day: 0, value: 892_000 },
];
export const sampleProj: CashPoint[] = [
  { day: 0, value: 892_000 },
  { day: 15, value: 838_000 },
  { day: 30, value: 760_000 },
  { day: 45, value: 690_000 },
  { day: 60, value: 720_000 },
  { day: 75, value: 640_000 },
  { day: 90, value: 612_000 },
];
export const sampleNetflow: NetFlowPoint[] = [
  { day: -90, net: 0 },
  { day: -82, net: 25 },
  { day: -67, net: 20 },
  { day: -52, net: 36 },
  { day: -37, net: 10 },
  { day: -22, net: 46 },
  { day: -7, net: 49 },
  { day: 0, net: 47 },
  { day: 8, net: -22 },
  { day: 23, net: -44 },
  { day: 38, net: -48 },
  { day: 53, net: 26 },
  { day: 68, net: -42 },
  { day: 83, net: -30 },
  { day: 90, net: -28 },
];

const VBH = 340;
const PAD_L = 58;
const PAD_R = 20;
const PAD_T = 34;
const PAD_B = 54;
const RIB_BAND_H = 72;

const MAX_V = 1_000_000;
const MIN_V = 400_000;
const MAX_NET = 52;

const fmtK = (v: number) =>
  v >= 1_000_000 ? `$${(v / 1_000_000).toFixed(2)}M` : `$${Math.round(v / 1000)}K`;

export function FinancialSituationChart({
  hist = sampleHist,
  proj = sampleProj,
  netflow = sampleNetflow,
  runwayFloor = 480_000,
  endLabelTop,
  endLabelBottom = "5.8 mo left",
  state = "ready",
  onTodayClick,
}: FinancialSituationChartProps) {
  const { ref, width: VBW } = useChartSize({ min: 820, fallback: 1280 });
  const reduce = usePrefersReducedMotion();
  const svgRef = useRef<SVGSVGElement | null>(null);
  const [hover, setHover] = useState<number | null>(null);
  const [drawn, setDrawn] = useState(reduce);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  // ─── States ───
  if (state !== "ready") {
    const message =
      state === "loading"
        ? "Loading 180 days of cash position…"
        : state === "error"
          ? "Couldn't load financial situation. Check the connection."
          : "No financial data yet — connect a source to see your cash position.";
    return (
      <div className="finsit-chart-area">
        <div className={`finsit-state finsit-state--${state}`}>
          <span className="finsit-state-mk" />
          <p>{message}</p>
        </div>
      </div>
    );
  }

  // ─── Geometry ───
  const R = VBW - PAD_R;
  const plotW = R - PAD_L;
  const base = PAD_T + (VBH - PAD_T - PAD_B);
  const balBot = base - RIB_BAND_H - 14;
  const x = (d: number) => PAD_L + ((d + 90) / 180) * plotW;
  const y = (v: number) => PAD_T + (1 - (v - MIN_V) / (MAX_V - MIN_V)) * (balBot - PAD_T);
  const fy = y(runwayFloor);

  // Ribbon zone
  const ribTop = balBot + 14;
  const ribBot = base;
  const ribMid = ribTop + RIB_BAND_H * 0.46;
  const ribUp = ribMid - ribTop;
  const ribDn = ribBot - ribMid;
  const ny0 = (v: number) =>
    v >= 0 ? ribMid - (v / MAX_NET) * ribUp : ribMid - (v / MAX_NET) * ribDn;
  const tx = x(0);

  // Coordinates
  const hp = hist.map((p) => [x(p.day), y(p.value)] as const);
  const pp = proj.map((p) => [x(p.day), y(p.value)] as const);

  // Ribbon polygons (split at today)
  const nfp = netflow.map((f) => [x(f.day), ny0(f.net)] as const);
  const todayIdx = netflow.findIndex((f) => f.day === 0);
  const ribbonPath = (from: number, to: number) => {
    let d = `M ${nfp[from][0].toFixed(1)} ${ribMid.toFixed(1)}`;
    for (let i = from; i <= to; i++) d += ` L ${nfp[i][0].toFixed(1)} ${nfp[i][1].toFixed(1)}`;
    d += ` L ${nfp[to][0].toFixed(1)} ${ribMid.toFixed(1)} Z`;
    return d;
  };
  const aPath = ribbonPath(0, todayIdx);
  const pPath = ribbonPath(todayIdx, nfp.length - 1);

  // Combined point list for crosshair
  const allPts = useMemo(() => [...hist, ...proj.slice(1)], [hist, proj]);

  // History line length for draw-in animation
  const histLineLen = plotW * 1.4;

  // Hover
  const handleMove = (e: React.MouseEvent) => {
    const svg = svgRef.current;
    if (!svg) return;
    const rb = svg.getBoundingClientRect();
    const sc = rb.width / VBW;
    const mx = (e.clientX - rb.left) / sc;
    let best = 0;
    let bestD = Infinity;
    allPts.forEach((p, i) => {
      const d = Math.abs(x(p.day) - mx);
      if (d < bestD) {
        bestD = d;
        best = i;
      }
    });
    setHover(best);
  };

  // Area path under historical line
  const histAreaD =
    `M ${hp[0][0].toFixed(1)} ${base} ` +
    hp.map(([px, py]) => `L ${px.toFixed(1)} ${py.toFixed(1)}`).join(" ") +
    ` L ${hp[hp.length - 1][0].toFixed(1)} ${base} Z`;

  const histPoints = hp.map(([px, py]) => `${px.toFixed(1)},${py.toFixed(1)}`).join(" ");
  const projPoints = pp.map(([px, py]) => `${px.toFixed(1)},${py.toFixed(1)}`).join(" ");
  const ribbonHistPoints = nfp
    .slice(0, todayIdx + 1)
    .map(([px, py]) => `${px.toFixed(1)},${py.toFixed(1)}`)
    .join(" ");
  const ribbonProjPoints = nfp
    .slice(todayIdx)
    .map(([px, py]) => `${px.toFixed(1)},${py.toFixed(1)}`)
    .join(" ");

  // Today + end positions
  const ny = hp[hp.length - 1][1];
  const endP = pp[pp.length - 1];
  const resolvedEndTop = endLabelTop ?? fmtK(proj[proj.length - 1].value);

  return (
    <div className="finsit-chart-area" ref={ref}>
      <svg
        ref={svgRef}
        viewBox={`0 0 ${VBW} ${VBH}`}
        style={{ display: "block", width: "100%", height: VBH, overflow: "visible" }}
        onMouseMove={handleMove}
        onMouseLeave={() => setHover(null)}
      >
        <defs>
          <linearGradient id="fsArea" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stopColor="#1D9E75" stopOpacity={0.22} />
            <stop offset="100%" stopColor="#1D9E75" stopOpacity={0} />
          </linearGradient>
          <linearGradient id="fsLine" x1="0" y1="0" x2="1" y2="0">
            <stop offset="0%" stopColor="#1D9E75" />
            <stop offset="100%" stopColor="#11805f" />
          </linearGradient>
          <pattern
            id="fsHatchG"
            width={6}
            height={6}
            patternTransform="rotate(45)"
            patternUnits="userSpaceOnUse"
          >
            <rect width="6" height="6" fill="#1D9E75" fillOpacity={0.1} />
            <line x1="0" y1="0" x2="0" y2="6" stroke="#1D9E75" strokeWidth={2} strokeOpacity={0.4} />
          </pattern>
          <pattern
            id="fsHatchR"
            width={6}
            height={6}
            patternTransform="rotate(45)"
            patternUnits="userSpaceOnUse"
          >
            <rect width="6" height="6" fill="#d64545" fillOpacity={0.08} />
            <line x1="0" y1="0" x2="0" y2="6" stroke="#d64545" strokeWidth={2} strokeOpacity={0.38} />
          </pattern>
          <clipPath id="fsAbove">
            <rect x={PAD_L} y={ribTop} width={plotW} height={ribUp} />
          </clipPath>
          <clipPath id="fsBelow">
            <rect x={PAD_L} y={ribMid} width={plotW} height={ribDn} />
          </clipPath>
        </defs>

        {/* Full-width gridlines + left axis labels */}
        {[1_000_000, 800_000, 600_000, 400_000].map((v) => {
          const yy = y(v);
          return (
            <g key={v}>
              <line x1={PAD_L} y1={yy} x2={R} y2={yy} stroke="rgba(0,0,0,0.06)" strokeWidth={1} />
              <text
                x={PAD_L - 10}
                y={yy + 3.5}
                textAnchor="end"
                fontFamily="JetBrains Mono, monospace"
                fontSize={11}
                fontWeight={500}
                letterSpacing="0.04em"
                fill="#5a5d65"
              >
                {fmtK(v)}
              </text>
            </g>
          );
        })}

        {/* ── NET-FLOW RIBBON (bottom band) ── */}
        <g opacity={drawn ? 1 : 0} style={{ transition: "opacity .6s ease .5s" }}>
          {/* zero baseline */}
          <line x1={PAD_L} y1={ribMid} x2={R} y2={ribMid} stroke="rgba(0,0,0,0.18)" strokeWidth={0.75} />
          <text
            x={PAD_L - 10}
            y={ribMid + 3}
            textAnchor="end"
            fontFamily="JetBrains Mono, monospace"
            fontSize={8.5}
            fontWeight={500}
            fill="#8a8d94"
          >
            NET $0
          </text>
          {/* Actual: solid green above, solid red below */}
          <path d={aPath} fill="#1D9E75" fillOpacity={0.34} clipPath="url(#fsAbove)" />
          <path d={aPath} fill="#d64545" fillOpacity={0.3} clipPath="url(#fsBelow)" />
          {/* Projected: hatched */}
          <path d={pPath} fill="url(#fsHatchG)" clipPath="url(#fsAbove)" />
          <path d={pPath} fill="url(#fsHatchR)" clipPath="url(#fsBelow)" />
          {/* Outline curves */}
          <polyline
            points={ribbonHistPoints}
            fill="none"
            stroke="#2b7a5e"
            strokeWidth={1.4}
            strokeLinejoin="round"
          />
          <polyline
            points={ribbonProjPoints}
            fill="none"
            stroke="#2b7a5e"
            strokeWidth={1.4}
            strokeDasharray="4 3"
            opacity={0.7}
            strokeLinejoin="round"
          />
          {/* Small label */}
          <text
            x={PAD_L + 4}
            y={ribTop + 9}
            fontFamily="JetBrains Mono, monospace"
            fontSize={8.5}
            fontWeight={600}
            letterSpacing="0.06em"
            fill="#8a8d94"
          >
            CASH FLOW · IN − OUT PER PERIOD
          </text>
        </g>

        {/* Runway floor */}
        <line
          x1={PAD_L}
          y1={fy}
          x2={R}
          y2={fy}
          stroke="#d64545"
          strokeWidth={1.4}
          strokeDasharray="5 4"
          opacity={0.7}
        />
        <text
          x={PAD_L + 2}
          y={fy - 7}
          fontFamily="JetBrains Mono, monospace"
          fontSize={9}
          fontWeight={600}
          letterSpacing="0.06em"
          fill="#c0413e"
        >
          RUNWAY FLOOR · {fmtK(runwayFloor)}
        </text>

        {/* TODAY vertical divider */}
        <line
          x1={tx}
          y1={PAD_T - 4}
          x2={tx}
          y2={base}
          stroke="#5B7CB0"
          strokeWidth={1}
          strokeDasharray="3 3"
          opacity={0.5}
        />
        <text
          x={tx}
          y={PAD_T - 12}
          textAnchor="middle"
          fontFamily="JetBrains Mono, monospace"
          fontSize={9}
          fontWeight={600}
          letterSpacing="0.1em"
          fill="#5a5d65"
        >
          TODAY
        </text>

        {/* Area under history */}
        <path
          d={histAreaD}
          fill="url(#fsArea)"
          opacity={drawn ? 1 : 0}
          style={{ transition: "opacity .6s ease 1.15s" }}
        />

        {/* Historical line — draws in on load */}
        <polyline
          points={histPoints}
          fill="none"
          stroke="url(#fsLine)"
          strokeWidth={3}
          strokeLinejoin="round"
          strokeLinecap="round"
          style={
            reduce
              ? undefined
              : {
                  strokeDasharray: histLineLen,
                  strokeDashoffset: drawn ? 0 : histLineLen,
                  transition: "stroke-dashoffset 1.1s cubic-bezier(.4,.1,.2,1) .15s",
                }
          }
        />
        {/* Projected line — dashed */}
        <polyline
          points={projPoints}
          fill="none"
          stroke="#1D9E75"
          strokeWidth={2.4}
          strokeDasharray="6 5"
          strokeLinejoin="round"
          strokeLinecap="round"
          opacity={drawn ? 0.65 : 0}
          style={{ transition: "opacity .5s ease 1.1s" }}
        />

        {/* History nodes (skip last — that's TODAY) */}
        {hp.slice(0, -1).map(([px, py], i) => (
          <rect
            key={`h${i}`}
            x={px - 3}
            y={py - 3}
            width={6}
            height={6}
            rx={0.5}
            fill="#fff"
            stroke="#1D9E75"
            strokeWidth={1.6}
            opacity={drawn ? 1 : 0}
            style={{ transition: `opacity .4s ease ${0.85 + i * 0.04}s` }}
          />
        ))}
        {/* Projection nodes (skip first & last) */}
        {pp.slice(1, -1).map(([px, py], i) => (
          <rect
            key={`p${i}`}
            x={px - 3}
            y={py - 3}
            width={6}
            height={6}
            rx={0.5}
            fill="#fff"
            stroke="#1D9E75"
            strokeWidth={1.6}
            opacity={drawn ? 0.6 : 0}
            style={{ transition: `opacity .4s ease ${1.2 + i * 0.04}s` }}
          />
        ))}

        {/* Projection end — square + value + runway label */}
        <g opacity={drawn ? 1 : 0} style={{ transition: "opacity .6s ease 1.45s" }}>
          <rect
            x={endP[0] - 5}
            y={endP[1] - 5}
            width={10}
            height={10}
            rx={0.5}
            fill="#fff"
            stroke="#1D9E75"
            strokeWidth={2}
          />
          <text
            x={endP[0] - 9}
            y={endP[1] - 9}
            textAnchor="end"
            fontFamily="JetBrains Mono, monospace"
            fontSize={10}
            fontWeight={600}
            fill="#5a5d65"
          >
            {resolvedEndTop}
          </text>
          <text
            x={endP[0] - 9}
            y={endP[1] + 10}
            textAnchor="end"
            fontFamily="Inter, sans-serif"
            fontSize={13}
            fontWeight={600}
            fill="#b3322e"
          >
            {endLabelBottom}
          </text>
        </g>

        {/* TODAY beacon — pulsing rings + filled square + value chip */}
        <g
          opacity={drawn ? 1 : 0}
          style={{ transition: "opacity .5s ease 1.15s", cursor: onTodayClick ? "pointer" : "default" }}
          onClick={onTodayClick}
        >
          {!reduce && (
            <>
              <circle cx={tx} cy={ny} r={6} fill="none" stroke="#1D9E75" strokeWidth={1.8}>
                <animate attributeName="r" values="6;24" dur="2.2s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.5;0" dur="2.2s" repeatCount="indefinite" />
              </circle>
              <circle cx={tx} cy={ny} r={6} fill="none" stroke="#1D9E75" strokeWidth={1.8}>
                <animate attributeName="r" values="6;24" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
                <animate attributeName="opacity" values="0.5;0" dur="2.2s" begin="1.1s" repeatCount="indefinite" />
              </circle>
            </>
          )}
          <rect x={tx - 7} y={ny - 7} width={14} height={14} rx={2} fill="#1D9E75" stroke="#fff" strokeWidth={2} />
          {/* Value chip */}
          <rect x={tx - 31} y={ny - 36} width={62} height={22} rx={3} fill="#fffdf8" stroke="#b88a2a" strokeWidth={0.8} />
          <rect x={tx - 31} y={ny - 36} width={3} height={22} rx={1} fill="#5B7CB0" />
          <text
            x={tx + 2}
            y={ny - 21}
            textAnchor="middle"
            fontFamily="Inter, sans-serif"
            fontSize={13}
            fontWeight={600}
            fill="#15171c"
          >
            {fmtK(hist[hist.length - 1].value)}
          </text>
        </g>

        {/* X labels */}
        {([
          [-90, "90d ago"],
          [-45, "45d ago"],
          [45, "+45d"],
          [90, "+90d"],
        ] as const).map(([d, l]) => (
          <text
            key={d}
            x={x(d)}
            y={base + 20}
            textAnchor="middle"
            fontFamily="JetBrains Mono, monospace"
            fontSize={11}
            fontWeight={500}
            fill="#5a5d65"
          >
            {l}
          </text>
        ))}
        <text
          x={tx}
          y={base + 20}
          textAnchor="middle"
          fontFamily="JetBrains Mono, monospace"
          fontSize={11}
          fontWeight={600}
          fill="#15171c"
        >
          today
        </text>

        {/* Crosshair on hover */}
        {hover !== null && (
          <g>
            <line
              x1={x(allPts[hover].day)}
              y1={PAD_T}
              x2={x(allPts[hover].day)}
              y2={base}
              stroke="#5B7CB0"
              strokeWidth={1}
              strokeDasharray="3 3"
              opacity={0.7}
            />
            <rect
              x={x(allPts[hover].day) - 6.5}
              y={y(allPts[hover].value) - 6.5}
              width={13}
              height={13}
              rx={1.5}
              fill="#fff"
              stroke="#5B7CB0"
              strokeWidth={2.2}
            />
          </g>
        )}

        {/* Invisible overlay for mouse capture */}
        <rect
          x={PAD_L}
          y={PAD_T}
          width={plotW}
          height={base - PAD_T}
          fill="transparent"
          style={{ cursor: "crosshair" }}
        />
      </svg>

      {/* Compact tooltip — value, day label, actual/projected tag */}
      {hover !== null && (() => {
        const p = allPts[hover];
        const svgRect = svgRef.current?.getBoundingClientRect();
        if (!svgRect) return null;
        const sc = svgRect.width / VBW;
        const sx = x(p.day) * sc;
        const sy = y(p.value) * sc;
        const future = p.day > 0;
        const dayLabel = p.day === 0 ? "Today" : p.day < 0 ? `${-p.day} days ago` : `+${p.day} days`;
        return (
          <div className="finsit-tip" style={{ display: "block", left: Math.max(60, Math.min(svgRect.width - 60, sx)), top: sy }}>
            <div className="tv">{fmtK(p.value)}</div>
            <div className="td">{dayLabel}</div>
            <div className="tg" style={{ color: future ? "#9fb4d6" : "#7fd3b0" }}>
              {future ? "projected" : "actual"}
            </div>
          </div>
        );
      })()}
    </div>
  );
}
