"use client";

/* ════════════════════════════════════════════════════════════════════════
   MarginWaterfall — Finance Tier-1 instrument.

   Question it answers: "Where does $1 of revenue actually go before it
   becomes profit?" — a left-to-right cascade with revenue as the full bar,
   each cost layer (COGS, shipping, marketing, overhead) removing value,
   and the final bar showing true net profit.

   Per the Chart Standard §2:
     - viewBox === pixel width (useChartSize)
     - typed WaterfallStep[] data with sample export
     - 4 states
     - reduced-motion safe — bars stagger in on mount
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";

export type StepKind = "total" | "cost" | "milestone" | "net";
export type ChartState = "ready" | "loading" | "empty" | "error";

export interface WaterfallStep {
  label: string;
  /** For "cost" steps: amount to subtract (positive). For "total"/"milestone"/"net": absolute height. */
  value: number;
  kind: StepKind;
  /** Display label for the value (e.g. "$245K" or "−$89K"). */
  display: string;
  /** Sub-label below the value. */
  sub?: string;
}

export interface MarginWaterfallProps {
  steps?: WaterfallStep[];
  state?: ChartState;
}

export const sampleWaterfallSteps: WaterfallStep[] = [
  { label: "Revenue", value: 245, kind: "total", display: "$245K", sub: "MTD" },
  { label: "COGS", value: 89, kind: "cost", display: "−$89K", sub: "36.5%" },
  { label: "CM1", value: 156, kind: "milestone", display: "$156K", sub: "63.5%" },
  { label: "Shipping", value: 28, kind: "cost", display: "−$28K", sub: "11.4%" },
  { label: "CM2", value: 128, kind: "milestone", display: "$128K", sub: "52.1%" },
  { label: "Marketing", value: 42, kind: "cost", display: "−$42K", sub: "17.2%" },
  { label: "CM3", value: 86, kind: "milestone", display: "$86K", sub: "34.9%" },
  { label: "Overhead", value: 21, kind: "cost", display: "−$21K", sub: "8.6%" },
  { label: "Net profit", value: 65, kind: "net", display: "$65K", sub: "26.5%" },
];

const VBH = 320;
const PAD_T = 50;
const PAD_B = 72;
const PAD_X = 24;
const BAR_GAP = 14;

const COLOR: Record<StepKind, string> = {
  total: "#1D9E75",
  cost: "#D85A30",
  milestone: "#5B7CB0",
  net: "#157a5b",
};

export function MarginWaterfall({ steps = sampleWaterfallSteps, state = "ready" }: MarginWaterfallProps) {
  const { ref, width: VBW } = useChartSize({ min: 640, fallback: 1000 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(reduce);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  if (state !== "ready" || steps.length === 0) {
    const message =
      state === "loading"
        ? "Loading margin breakdown…"
        : state === "error"
          ? "Couldn't load margin waterfall."
          : "No data yet — connect a source to see your margin cascade.";
    return (
      <div className="wf-chart-host" ref={ref}>
        <div className={`wf-state wf-state--${state === "ready" ? "empty" : state}`}>
          <span className="wf-state-mk" />
          <p>{message}</p>
        </div>
      </div>
    );
  }

  // Scales
  const n = steps.length;
  const plotW = VBW - 2 * PAD_X;
  const barW = (plotW - (n - 1) * BAR_GAP) / n;
  const plotH = VBH - PAD_T - PAD_B;
  const maxV = Math.max(...steps.filter((s) => s.kind !== "cost").map((s) => s.value));
  const yScale = (v: number) => (v / maxV) * plotH;
  const base = VBH - PAD_B;

  // Compute each bar's y position (top) and height
  // For "total"/"milestone"/"net": absolute bar from base.
  // For "cost": floating bar at the level it removes from (between prev milestone and next milestone).
  // We compute the running balance.
  let runningTop = 0; // height of current milestone in chart units
  const layout = steps.map((s) => {
    if (s.kind === "total" || s.kind === "milestone" || s.kind === "net") {
      const h = yScale(s.value);
      runningTop = h;
      return { top: base - h, height: h, isFloating: false };
    }
    // cost: shrinks running top by yScale(value)
    const h = yScale(s.value);
    const top = base - runningTop;
    runningTop -= h;
    return { top, height: h, isFloating: true };
  });

  return (
    <div className="wf-chart-host" ref={ref}>
      <svg
        viewBox={`0 0 ${VBW} ${VBH}`}
        style={{ display: "block", width: "100%", height: VBH, overflow: "visible" }}
      >
        {/* baseline */}
        <line x1={PAD_X} y1={base} x2={VBW - PAD_X} y2={base} stroke="rgba(0,0,0,0.18)" strokeWidth={1} />

        {/* connector lines between bars (top-of-prev → top-of-next, for milestone/cost continuity) */}
        {steps.map((s, i) => {
          if (i === 0) return null;
          const prev = layout[i - 1];
          const curr = layout[i];
          const x1 = PAD_X + (i - 1) * (barW + BAR_GAP) + barW;
          const x2 = PAD_X + i * (barW + BAR_GAP);
          // For cost: connect previous milestone top → cost top
          // For milestone after cost: connect cost bottom → milestone top
          // Simplification: connect top edges
          const y1 = steps[i - 1].kind === "cost" ? prev.top + prev.height : prev.top;
          const y2 = s.kind === "cost" ? curr.top : curr.top;
          return (
            <line
              key={`c${i}`}
              x1={x1}
              y1={y1}
              x2={x2}
              y2={y2}
              stroke="rgba(0,0,0,0.18)"
              strokeWidth={1}
              strokeDasharray="3 3"
              opacity={drawn ? 0.5 : 0}
              style={{ transition: `opacity .4s ease ${0.4 + i * 0.05}s` }}
            />
          );
        })}

        {/* bars */}
        {steps.map((s, i) => {
          const x = PAD_X + i * (barW + BAR_GAP);
          const l = layout[i];
          return (
            <g key={s.label}>
              {/* bar rect — animates from height 0 */}
              <rect
                x={x}
                y={drawn ? l.top : base}
                width={barW}
                height={drawn ? l.height : 0}
                rx={2}
                fill={COLOR[s.kind]}
                opacity={s.kind === "cost" ? 0.92 : 1}
                style={
                  reduce
                    ? undefined
                    : {
                        transition: `y .55s cubic-bezier(.4,.1,.2,1) ${0.1 + i * 0.06}s, height .55s cubic-bezier(.4,.1,.2,1) ${0.1 + i * 0.06}s`,
                      }
                }
              />

              {/* Value label above the bar (or inside for tall ones) */}
              <text
                x={x + barW / 2}
                y={l.top - 8}
                textAnchor="middle"
                fontFamily="Inter, sans-serif"
                fontSize={s.kind === "total" || s.kind === "net" ? 14 : 12}
                fontWeight={s.kind === "total" || s.kind === "net" ? 500 : 400}
                fill="#15171c"
                opacity={drawn ? 1 : 0}
                style={{ transition: `opacity .3s ease ${0.4 + i * 0.06}s` }}
              >
                {s.display}
              </text>

              {/* X label — label name + sub */}
              <text
                x={x + barW / 2}
                y={base + 22}
                textAnchor="middle"
                fontFamily="JetBrains Mono, monospace"
                fontSize={10}
                fontWeight={s.kind === "milestone" || s.kind === "total" || s.kind === "net" ? 600 : 500}
                letterSpacing="0.06em"
                fill={s.kind === "cost" ? "#9e2727" : "#15171c"}
              >
                {s.label}
              </text>
              {s.sub && (
                <text
                  x={x + barW / 2}
                  y={base + 38}
                  textAnchor="middle"
                  fontFamily="JetBrains Mono, monospace"
                  fontSize={9}
                  letterSpacing="0.04em"
                  fill="#8a8d94"
                >
                  {s.sub}
                </text>
              )}
            </g>
          );
        })}
      </svg>
    </div>
  );
}
