"use client";

/**
 * <NetProfitByDay> — Tier-2 in-hero chart for daily net profit.
 *
 * Lives INSIDE the Finance dept-hero (white-on-green register). Shows the
 * trajectory behind the hero number — same KPI, but with time, variance,
 * an average reference line, and an honest "today so far" partial-day
 * beacon at the end.
 *
 * Conforms to CHART-STANDARD §2:
 *   - viewBox === real px width via useChartSize (rule 2)
 *   - <ChartStates> wraps the SVG (rule 5)
 *   - usePrefersReducedMotion gates the line draw-in + area fade + beacon
 *   - No `preserveAspectRatio="none"`; no fixed-width viewBox
 *   - Props-driven; sample data exported (§4 data contract)
 */

import { useEffect, useState } from "react";
import { useChartSize, usePrefersReducedMotion } from "@/lib/useChartSize";
import { ChartStates, type ChartState } from "./_kit/ChartStates";

export interface DailyPoint {
  /** Day label shown in the x-axis ticks, e.g. "May 1". Used for selected x labels only. */
  label: string;
  /** Net profit in dollars for that day. null = day hasn't happened yet (future). */
  value: number | null;
  /** Mark the partial "today so far" point — drives the end beacon + inline label. */
  isToday?: boolean;
}

export interface NetProfitByDayProps {
  data: DailyPoint[];
  /** Average per-day in dollars (drives the dashed reference line). */
  avg: number;
  /** Max value for the y-axis (drives gridlines). Default rounds to nearest $1K above max(value). */
  yMax?: number;
  /** Y-axis tick values (drives label positions). Default 4 ticks. */
  yTicks?: number[];
  /** Indices in `data` to label on the x-axis. Defaults to [0, end] only. */
  xLabelIdx?: number[];
  /** Chart title shown above the SVG. */
  title?: string;
  /** Inline label next to the today beacon, e.g. "today · $1.0K so far". */
  todayNote?: string;
  state?: ChartState;
  height?: number;
  /** Aria label / fallback copy. */
  label?: string;
}

export const sampleNetProfitByDay: DailyPoint[] = [
  { label: "May 1", value: 3100 },
  { label: "May 2", value: 3800 },
  { label: "May 3", value: 2900 },
  { label: "May 4", value: 5400 },
  { label: "May 5", value: 4600 },
  { label: "May 6", value: 2300 },
  { label: "May 7", value: 1800 },
  { label: "May 8", value: 2700 },
  { label: "May 9", value: 3500 },
  { label: "May 10", value: 2400 },
  { label: "May 11", value: 4900 },
  { label: "May 12", value: 4100 },
  { label: "May 13", value: 2000 },
  { label: "May 14", value: 1500 },
  { label: "May 15", value: 3000 },
  { label: "May 16", value: 4300 },
  { label: "May 17", value: 3600 },
  { label: "May 18", value: 5700 },
  { label: "May 19", value: 4400 },
  { label: "May 20", value: 2500 },
  { label: "May 21", value: 2100 },
  { label: "May 22", value: 3200 },
  { label: "May 23", value: 3700 },
  { label: "May 24", value: 2800 },
  { label: "May 25", value: 4200 },
  { label: "May 26", value: 1000, isToday: true },
];

export function NetProfitByDay({
  data,
  avg,
  yMax,
  yTicks,
  xLabelIdx,
  title = "Net profit by day",
  todayNote,
  state = "ready",
  height = 128,
  label = "Net profit by day",
}: NetProfitByDayProps) {
  const { ref, width } = useChartSize({ min: 480, fallback: 760 });
  const reduce = usePrefersReducedMotion();
  const [drawn, setDrawn] = useState(false);

  useEffect(() => {
    if (reduce) {
      setDrawn(true);
      return;
    }
    setDrawn(false);
    const r = requestAnimationFrame(() => requestAnimationFrame(() => setDrawn(true)));
    return () => cancelAnimationFrame(r);
  }, [reduce]);

  const W = Math.max(480, width);
  const H = height;
  const padL = 44;
  const padR = 14;
  const padT = 10;
  const padB = 24;
  const plotW = W - padL - padR;
  const plotH = H - padT - padB;
  const base = padT + plotH;

  const realPts = data.filter((d) => d.value !== null) as { label: string; value: number; isToday?: boolean }[];
  const maxValue = Math.max(...realPts.map((d) => d.value));
  const top = yMax ?? Math.ceil((maxValue * 1.06) / 1000) * 1000;
  const ticks = yTicks ?? [0, top / 3, (top * 2) / 3, top];

  const x = (i: number) =>
    padL + (data.length === 1 ? plotW / 2 : (i / (data.length - 1)) * plotW);
  const y = (v: number) => padT + (1 - v / top) * plotH;

  const pts = data
    .map((d, i) => (d.value === null ? null : [x(i), y(d.value)] as [number, number]))
    .filter((p): p is [number, number] => p !== null);
  const linePath = "M " + pts.map((p) => `${p[0].toFixed(1)} ${p[1].toFixed(1)}`).join(" L ");
  const areaPath =
    linePath +
    ` L ${pts[pts.length - 1][0].toFixed(1)} ${base.toFixed(1)} L ${pts[0][0].toFixed(1)} ${base.toFixed(1)} Z`;
  const lineLen = plotW + 80;

  const todayIdx = data.findIndex((d) => d.isToday);
  const todayPoint =
    todayIdx >= 0 && data[todayIdx].value !== null
      ? ([x(todayIdx), y(data[todayIdx].value as number)] as [number, number])
      : null;

  const xLabels = xLabelIdx ?? [0, data.length - 1];
  const fmt = (v: number) => (v >= 1000 ? `$${(v / 1000).toFixed(0)}K` : `$${v}`);
  const avgY = y(avg);

  return (
    <div ref={ref} className="dept-hero-chart">
      {title && <div className="dhc-title">{title}</div>}
      <ChartStates state={state} height={H} label={label}>
        <svg viewBox={`0 0 ${W} ${H}`} width="100%" height={H} style={{ display: "block", overflow: "visible" }}>
          <defs>
            <linearGradient id="np-grad" x1="0" y1="0" x2="0" y2="1">
              <stop offset="0%" stopColor="rgba(255,255,255,0.26)" />
              <stop offset="100%" stopColor="rgba(255,255,255,0.02)" />
            </linearGradient>
          </defs>

          {/* Gridlines + y labels */}
          {ticks.map((v, i) => {
            const yy = y(v);
            return (
              <g key={i}>
                <line className="dhc-grid" x1={padL} y1={yy} x2={W - padR} y2={yy} />
                <text className="dhc-axis-label" x={0} y={yy + 3}>
                  {fmt(v)}
                </text>
              </g>
            );
          })}

          {/* Area */}
          <path
            d={areaPath}
            fill="url(#np-grad)"
            style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.7s 0.4s" }}
          />

          {/* Average reference line */}
          <line className="dhc-avg" x1={padL} y1={avgY} x2={W - padR} y2={avgY} />
          <text className="dhc-avg-label" x={W - padR} y={avgY - 5} textAnchor="end">
            AVG {fmt(avg)}/DAY
          </text>

          {/* Line with draw-in */}
          <path
            className="dhc-line"
            d={linePath}
            style={{
              strokeDasharray: lineLen,
              strokeDashoffset: drawn ? 0 : lineLen,
              transition: "stroke-dashoffset 1.2s cubic-bezier(.3,.7,.3,1)",
            }}
          />

          {/* Today beacon */}
          {todayPoint && (
            <g style={{ opacity: drawn ? 1 : 0, transition: "opacity 0.4s 1.1s" }}>
              <circle className="dhc-dot-ring" cx={todayPoint[0]} cy={todayPoint[1]} r={6.5} />
              <circle className="dhc-dot" cx={todayPoint[0]} cy={todayPoint[1]} r={3.2} />
              {todayNote && (
                <text className="dhc-end-label" x={todayPoint[0] - 8} y={todayPoint[1] + 4} textAnchor="end">
                  {todayNote}
                </text>
              )}
            </g>
          )}

          {/* X labels */}
          {xLabels.map((i) => {
            const d = data[i];
            if (!d) return null;
            const anchor: "start" | "middle" | "end" =
              i === 0 ? "start" : i === data.length - 1 ? "end" : "middle";
            const isToday = d.isToday === true;
            return (
              <text
                key={i}
                className={`dhc-x-label${isToday ? " today" : ""}`}
                x={x(i)}
                y={base + 18}
                textAnchor={anchor}
              >
                {d.label}
              </text>
            );
          })}
        </svg>
      </ChartStates>
    </div>
  );
}
